module serial2parallel
(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output dout_parallel,
    output reg dout_valid
);

    reg [3:0] cnt;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 4'd0;
            dout_valid <= 1'b0;
        end
        else if (din_valid) begin
            case (cnt)
                4'd0: dout_parallel[0] <= din_serial;
                4'd1: dout_parallel[1] <= din_serial;
                4'd2: dout_parallel[2] <= din_serial;
                4'd3: dout_parallel[3] <= din_serial;
                4'd4: dout_parallel[4] <= din_serial;
                4'd5: dout_parallel[5] <= din_serial;
                4'd6: dout_parallel[6] <= din_serial;
                4'd7: dout_parallel[7] <= din_serial;
                default: ;
            endcase

            if (cnt == 4'd7) begin
                cnt <= 4'd0;
                dout_valid <= 1'b1;
            end
            else begin
                cnt <= cnt + 4'd1;
                dout_valid <= 1'b0;
            end
        end
        else begin
            cnt <= 4'd0;
            dout_valid <= 1'b0;
        end
    end

endmodule
